static <E> ImmutableList<E> asImmutableList(Object[] elements, int length) {
    if (length == 0) {
      return of();
    }
    if (length < elements.length) {
      elements = Arrays.copyOf(elements, length);
    }
    return new RegularImmutableList<E>(elements);
  }
